parameters.jsCode:
// Sources (by node name) + trigger payload
const prefs = $('Get Preferences').first().json.data;
const business = $('Get Business').first().json.data;
const wh = $('Webhook').first().json.body;
const brief = wh.brief || {};
const platform = (wh.platform || '').toLowerCase();

// Allow-list: reject unknown platforms early with a clear error
const allowed = ['instagram', 'facebook', 'linkedin', 'twitter'];
if (!allowed.includes(platform)) {
  throw new Error('Unsupported platform: ' + platform + '. Allowed: ' + allowed.join(', '));
}

// Platform-specific writing rules injected into the prompt
const rules = {
  instagram: 'Platform: Instagram. Warm and visual. Put the hook on the first line. Use 1-3 relevant emojis naturally. Keep the caption 80-150 words. End with the CTA. Then provide 5-10 relevant hashtags.',
  facebook: 'Platform: Facebook. Conversational and community-oriented. Up to ~180 words. Use 0-2 hashtags only. End with the CTA. Use emojis sparingly.',
  linkedin: 'Platform: LinkedIn. Professional, credible, value-first. Avoid hype and avoid emojis. 100-160 words. Provide 3-5 professional hashtags. End with a clear professional CTA.',
  twitter: 'Platform: X (Twitter). Punchy and concise. The ENTIRE post including any hashtags MUST be under 280 characters total. Use at most 1-2 hashtags. Lead with the hook, end with the CTA.'
};

return [{
  json: {
    slot_id: wh.slot_id,
    business_id: wh.business_id,
    platform: platform,
    business_name: business.name,
    industry: business.industry,
    brand_tone: prefs.brand_tone,
    hook: brief.hook || '',
    key_message: brief.key_message || '',
    emotional_angle: brief.emotional_angle || '',
    cta: brief.cta || '',
    platform_rules: rules[platform]
  }
}];

