// Context (by name) for identifiers + platform
const ctx = $('Merge Context').first().json;

// Grab the raw text GPT returned (OpenAI Responses API structure)
let raw;
try {
  raw = $input.first().json.output[0].content[0].text;
} catch (e) {
  throw new Error('Could not find AI response text — OpenAI output structure was unexpected.');
}

// Strip markdown fences if GPT adds them
const cleaned = (raw || '').replace(/```json/gi, '').replace(/```/g, '').trim();

// Parse JSON — fail clearly if GPT returned garbage
let out;
try {
  out = JSON.parse(cleaned);
} catch (e) {
  throw new Error('AI did not return valid JSON. Raw start: ' + cleaned.slice(0, 200));
}

// Validate caption
if (!out.caption || typeof out.caption !== 'string') {
  throw new Error('Caption missing or not a string.');
}
const hashtags = Array.isArray(out.hashtags) ? out.hashtags : [];

// Compute full length (caption + hashtags) and enforce the X/Twitter hard limit
const fullText = out.caption + (hashtags.length ? ' ' + hashtags.join(' ') : '');
const charCount = fullText.length;
if (ctx.platform === 'twitter' && charCount > 280) {
  throw new Error('Twitter caption exceeds 280 chars (' + charCount + '). Needs regeneration.');
}

return [{
  json: {
    slot_id: ctx.slot_id,
    business_id: ctx.business_id,
    platform: ctx.platform,
    caption: out.caption,
    hashtags: hashtags,
    char_count: charCount
  }
}];

// Single caption in -> single clean response out
const d = $input.first().json;
return [{
  json: {
    success: true,
    slot_id: d.slot_id,
    platform: d.platform,
    caption: d.caption,
    hashtags: d.hashtags,
    char_count: d.char_count
  }
}];
